import {
  type InferRecursiveInput,
  type InferRecursiveOutput,
  type RecurInput,
  type RecurOutput,
} from './types.ts';

/**
 * Recursive placeholder schema interface.
 */
export interface RecurSchema
  extends BaseSchema<RecurInput, RecurOutput, BaseIssue<unknown>> {
  /**
   * The schema type.
   */
  readonly type: 'recur';
  /**
   * The schema reference.
   */
  readonly reference: typeof recursive;
  /**
   * The expected property.
   */
  readonly expects: 'unknown';
}

/**
 * Recursive schema interface.
 */
export interface RecursiveSchema<
  TInput,
  TOutput,
  TIssue extends BaseIssue<unknown>,
  TWrapped extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
> extends BaseSchema<TInput, TOutput, TIssue> {
  /**
   * The schema type.
   */
  readonly type: 'recursive';
  /**
   * The schema reference.
   */
  readonly reference: typeof recursive;
  /**
   * The expected property.
   */
  readonly expects: 'unknown';
  /**
   * The wrapped schema.
   */
  readonly wrapped: TWrapped;
}

/**
 * Placeholder for a self reference in a recursive schema.
 */
export const Recur: RecurSchema = {
  kind: 'schema',
  type: 'recur',
  reference: recursive,
  expects: 'unknown',
  async: false,
  get '~standard'() {
    return _getStandardProps(this);
  },
  '~run'() {
    throw new Error('Recursive placeholders must be wrapped with recursive().');
  },
};

/**
 * Creates a recursive schema by resolving `Recur` placeholders.
 *
 * @param wrapped The schema containing recursive placeholders.
 *
 * @returns A recursive schema.
 */
// @__NO_SIDE_EFFECTS__
export function recursive<
  const TWrapped extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
>(
  wrapped: TWrapped
): RecursiveSchema<
  InferRecursiveInput<TWrapped>,
  InferRecursiveOutput<TWrapped>,
  InferIssue<TWrapped>,
  TWrapped
> {
  let schema: RecursiveSchema<
    InferRecursiveInput<TWrapped>,
    InferRecursiveOutput<TWrapped>,
    InferIssue<TWrapped>,
    TWrapped
  >;
  const references = new WeakMap<object, object>();

  const resolve = (value: unknown): unknown => {
    if (value === Recur) {
      return schema;
    }
    if (!value || typeof value !== 'object') {
      return value;
    }
    const reference = references.get(value);
    if (reference) {
      return reference;
    }
    const resolved = Array.isArray(value)
      ? []
      : Object.create(Object.getPrototypeOf(value));
    references.set(value, resolved);
    for (const key of Reflect.ownKeys(value)) {
      const descriptor = Object.getOwnPropertyDescriptor(value, key);
      if (descriptor && 'value' in descriptor) {
        descriptor.value = resolve(descriptor.value);
      }
      Object.defineProperty(resolved, key, descriptor!);
    }
    return resolved;
  };

  schema = {
    kind: 'schema',
    type: 'recursive',
    reference: recursive,
    expects: 'unknown',
    async: false,
    wrapped,
    get '~standard'() {
      return _getStandardProps(this);
    },
    '~run'(dataset, config) {
      return (resolve(wrapped) as TWrapped)['~run'](
        dataset,
        config
      ) as ReturnType<typeof schema['~run']>;
    },
  };
  return schema;
}

